css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: calc(var(--loader-size) * 1.35); height: calc(var(--loader-size) * .52); display: flex; align-items: center; justify-content: space-between; gap: 7px; filter: drop-shadow(0 0 10px color-mix(in srgb, var(--accent) 45%, transparent)); }
.loader span { width: 14%; aspect-ratio: 1; border-radius: 50%; background: var(--accent-2); animation: comet-pull calc(var(--speed) * 1.2) ease-in-out infinite; }
.loader span:nth-child(1) { animation-delay: -.4s; } .loader span:nth-child(2) { animation-delay: -.3s; } .loader span:nth-child(3) { animation-delay: -.2s; } .loader span:nth-child(4) { animation-delay: -.1s; }
.loader span:nth-child(5) { background: var(--accent); box-shadow: 0 0 18px var(--accent); }
@keyframes comet-pull { 0%,100% { transform: translateY(0) scale(.75); opacity: .45; } 45% { transform: translateY(-16px) scale(1.15); opacity: 1; } 70% { transform: translateY(7px) scale(.85); } }
